const debounce = require('./debounce');

describe('debounce()', () => {
  beforeEach(() => jest.useFakeTimers());
  afterEach(() => jest.useRealTimers());

  // Verifies function is not called before delay elapses
  it('does not call fn immediately', () => {
    const fn = jest.fn();
    const debounced = debounce(fn, 300);
    debounced();
    expect(fn).not.toHaveBeenCalled();
  });

  // Verifies function is called after delay
  it('calls fn after the delay', () => {
    const fn = jest.fn();
    const debounced = debounce(fn, 300);
    debounced();
    jest.advanceTimersByTime(300);
    expect(fn).toHaveBeenCalledTimes(1);
  });

  // Verifies rapid calls only trigger one execution
  it('only calls fn once for rapid successive calls', () => {
    const fn = jest.fn();
    const debounced = debounce(fn, 300);
    debounced(); debounced(); debounced();
    jest.advanceTimersByTime(300);
    expect(fn).toHaveBeenCalledTimes(1);
  });
});

